// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Red Properties ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Yellow Property ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Green Properties ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Purple Properties ---
const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Gold Properties ---
const hevronElonMamrei = {
  type: "property",
  name: "Hevron Elon Mamrei",
  colorGroup: "gold",
  price: 240,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronHiTech = {
  type: "property",
  name: "Hevron Hi Tech",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board events map ---
const boardEvents = {
  3: { type: "property", card: schemRoyalEstates },
  1: { type: "property", card: schemYosephGardens },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  29: { type: "property", card: jerusalemHills },
  28: { type: "property", card: jerusalemHillsOrchard },
  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Build 44 board positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Component ---
function CardModal({ card, onClose, mode, currentPlayer, updatePlayer, players, updatePlayers }) {
  if (!card) return null;

  const isProperty = mode === "property";

  const handleBuyProperty = () => {
    if (currentPlayer.money < card.price) {
      alert("Not enough money to buy this property!");
      return;
    }
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayer.index] = {
      ...currentPlayer,
      money: currentPlayer.money - card.price,
    };
    card.ownerIndex = currentPlayer.index;
    updatePlayers(updatedPlayers);
    alert(`${currentPlayer.name} bought ${card.name} for $${card.price}`);
    onClose();
  };

  const handlePayRent = () => {
    if (card.ownerIndex === null || card.ownerIndex === currentPlayer.index) {
      alert("No rent needed.");
      return;
    }
    const rentAmount = card.rent.base;
    if (currentPlayer.money < rentAmount) {
      alert("Not enough money to pay rent!");
      return;
    }
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayer.index].money -= rentAmount;
    updatedPlayers[card.ownerIndex].money += rentAmount;
    updatePlayers(updatedPlayers);
    alert(`${currentPlayer.name} paid $${rentAmount} rent to ${players[card.ownerIndex].name}`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>
        {isProperty && (
          <>
            <div style={{ height: 20, backgroundColor: card.colorGroup, marginBottom: 10, borderRadius: 4 }}></div>
            <p>Price: ${card.price}</p>
            <p>Rent: ${card.rent.base}</p>
            <p>Rent with 1 House: ${card.rent.house1}</p>
            <p>Rent with 2 Houses: ${card.rent.house2}</p>
            <p>Rent with 3 Houses: ${card.rent.house3}</p>
            <p>Rent with Hotel: ${card.rent.hotel}</p>
            <p>House Cost: ${card.buildCost.house}</p>
            <p>Hotel Cost: ${card.buildCost.hotel}</p>
            <p>Owner: {card.ownerIndex !== null ? `Player ${card.ownerIndex + 1}` : "None"}</p>
            <p>Your Money: ${currentPlayer.money}</p>
            {card.description && <p>{card.description}</p>}
            <button style={{ ...modalStyles.button, backgroundColor: "green" }} onClick={handleBuyProperty}>
              Buy Property
            </button>
            <button style={{ ...modalStyles.button, backgroundColor: "orange" }} onClick={handlePayRent}>
              Pay Rent
            </button>
            <button style={modalStyles.button} onClick={onClose}>
              Close
            </button>
          </>
        )}
      </div>
    </div>
  );
}

// --- Player Panel Modal ---
function PlayerPanelModal({ player, onClose }) {
  if (!player) return null;

  // Unique properties
  const ownedProperties = Array.from(
    new Set(
      Object.values(boardEvents)
        .map((e) => e.card)
        .filter((card) => card.ownerIndex === player.index)
    )
  );

  const calculateCurrentRent = (card) => {
    if (card.hotel) return card.rent.hotel;
    switch (card.houses) {
      case 3:
        return card.rent.house3;
      case 2:
        return card.rent.house2;
      case 1:
        return card.rent.house1;
      default:
        return card.rent.base;
    }
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{player.name}'s Properties</h2>
        {ownedProperties.length === 0 ? (
          <p>No properties owned.</p>
        ) : (
          <ul style={{ textAlign: "left" }}>
            {ownedProperties.map((prop, idx) => (
              <li key={idx} style={{ marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center" }}>
                  <div
                    style={{
                      width: 20,
                      height: 20,
                      backgroundColor: prop.colorGroup,
                      marginRight: 6,
                      borderRadius: 4,
                    }}
                  ></div>
                  <strong>{prop.name}</strong>
                </div>
                Price: ${prop.price}<br />
                Houses: {prop.houses}, Hotel: {prop.hotel ? "Yes" : "No"}<br />
                House Cost: ${prop.buildCost.house}, Hotel Cost: ${prop.buildCost.hotel}<br />
                Current Rent: ${calculateCurrentRent(prop)}
              </li>
            ))}
          </ul>
        )}
        <button style={modalStyles.button} onClick={onClose}>
          Close
        </button>
      </div>
    </div>
  );
}

// --- Trade Modal ---
function TradeModal({ players, onClose, executeTrade }) {
  const [fromPlayerIndex, setFromPlayerIndex] = useState("");
  const [toPlayerIndex, setToPlayerIndex] = useState("");
  const [propertyIndex, setPropertyIndex] = useState("");
  const [cash, setCash] = useState(0);

  const ownedProperties = fromPlayerIndex !== "" 
    ? Object.values(boardEvents)
        .map((e) => e.card)
        .filter((c) => c.ownerIndex === parseInt(fromPlayerIndex))
    : [];

  const handleTrade = () => {
    if (fromPlayerIndex === "" || toPlayerIndex === "" || propertyIndex === "") {
      alert("Please select all fields");
      return;
    }
    const from = parseInt(fromPlayerIndex);
    const to = parseInt(toPlayerIndex);
    const property = ownedProperties[propertyIndex];
    executeTrade(from, to, property, parseInt(cash));
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>Trade Property</h2>
        <select value={fromPlayerIndex} onChange={(e) => setFromPlayerIndex(e.target.value)}>
          <option value="">From Player</option>
          {players.map((p, i) => (
            <option key={i} value={i}>{p.name}</option>
          ))}
        </select>
        <br /><br />
        <select value={toPlayerIndex} onChange={(e) => setToPlayerIndex(e.target.value)}>
          <option value="">To Player</option>
          {players.map((p, i) => (
            <option key={i} value={i}>{p.name}</option>
          ))}
        </select>
        <br /><br />
        <select value={propertyIndex} onChange={(e) => setPropertyIndex(e.target.value)}>
          <option value="">Property</option>
          {ownedProperties.map((prop, idx) => (
            <option key={idx} value={idx}>{prop.name}</option>
          ))}
        </select>
        <br /><br />
        <input type="number" placeholder="Cash Amount" value={cash} onChange={(e) => setCash(e.target.value)} />
        <br /><br />
        <button style={modalStyles.button} onClick={handleTrade}>Execute Trade</button>
        <button style={modalStyles.button} onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [qaMode, setQaMode] = useState(false);
  const [currentCard, setCurrentCard] = useState(null);
  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const [boardPositions, setBoardPositions] = useState(defaultBoardPositions);
  const [diceRolls, setDiceRolls] = useState([]);
  const [showPanel, setShowPanel] = useState(null);
  const [showTrade, setShowTrade] = useState(false);

  const availableColors = ["black", "purple", "blue", "brown", "orange", "red", "green"];
  const maxPlayers = 7;
  const scale = boardWidth / referenceSize;

  useEffect(() => {
    const handleResize = () => setBoardWidth(Math.min(window.innerWidth * 0.95, referenceSize));
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    if (players.some((p) => p.color === newPlayerColor)) {
      alert("Color taken!");
      return;
    }
    setPlayers([
      ...players,
      { name: newPlayerName, color: newPlayerColor, position: 0, zchutPoints: 1000, money: 2000, missTurn: false, index: players.length },
    ]);
    setNewPlayerName("");
    setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) {
      alert("At least 2 players required.");
      return;
    }
    setGameStarted(true);
  };

  const updateCurrentPlayer = (updatedPlayer) => {
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayerIndex] = updatedPlayer;
    setPlayers(updatedPlayers);
  };

  const movePlayerBy = (steps) => {
    if (steps <= 0 || players.length === 0) return;
    const speedMs = 220;
    const updatedPlayers = [...players];
    const startIndex = updatedPlayers[currentPlayerIndex].position;
    let stepCount = 0;

    const doStep = () => {
      stepCount++;
      updatedPlayers[currentPlayerIndex].position = (startIndex + stepCount) % 44;
      setPlayers([...updatedPlayers]);
      if (stepCount < steps) {
        setTimeout(doStep, speedMs);
      } else {
        const card = boardEvents[updatedPlayers[currentPlayerIndex].position];
        if (card) {
          setCurrentCard(card.card);
          setQaMode(true);
        }
      }
    };

    doStep();
  };

  const handleTrade = (fromIdx, toIdx, property, cashAmount) => {
    const updatedPlayers = [...players];
    updatedPlayers[fromIdx].money += cashAmount;
    updatedPlayers[toIdx].money -= cashAmount;
    property.ownerIndex = toIdx;
    setPlayers(updatedPlayers);
  };

  const rollDice = () => {
    const roll = Math.floor(Math.random() * 6) + 1;
    setDiceRolls([roll]);
    movePlayerBy(roll);
  };

  return (
    <div style={{ textAlign: "center", fontFamily: "Arial" }}>
      {!gameStarted && (
        <div>
          <h2>Setup Players</h2>
          <input placeholder="Player Name" value={newPlayerName} onChange={(e) => setNewPlayerName(e.target.value)} />
          <select value={newPlayerColor} onChange={(e) => setNewPlayerColor(e.target.value)}>
            <option value="">Select Color</option>
            {availableColors.map((c, i) => (
              <option key={i} value={c}>{c}</option>
            ))}
          </select>
          <button onClick={addPlayer}>Add Player</button>
          <ul>
            {players.map((p, i) => (
              <li key={i}>{p.name} ({p.color})</li>
            ))}
          </ul>
          <button onClick={startGame}>Start Game</button>
        </div>
      )}

      {gameStarted && (
        <div>
          <h2>Monopoly Board</h2>
          <div style={{ position: "relative", margin: "auto", width: boardWidth, height: boardWidth, border: "2px solid black" }}>
            <img src={boardImage} alt="Board" style={{ width: boardWidth, height: boardWidth }} />
            {players.map((p, i) => (
              <div key={i} style={{ position: "absolute", left: boardPositions[p.position].x * scale - 12, top: boardPositions[p.position].y * scale - 12, width: 24, height: 24, borderRadius: 12, backgroundColor: p.color, border: "2px solid white" }} title={p.name}></div>
            ))}
          </div>
          <br />
          <button onClick={rollDice}>Roll Dice</button>
          <button onClick={() => setShowPanel(currentPlayerIndex)}>View My Properties</button>
          <button onClick={() => setShowTrade(true)}>Trade</button>
        </div>
      )}

      {qaMode && (
        <CardModal
          card={currentCard}
          mode="property"
          currentPlayer={players[currentPlayerIndex]}
          updatePlayer={updateCurrentPlayer}
          players={players}
          updatePlayers={setPlayers}
          onClose={() => { setQaMode(false); setCurrentCard(null); }}
        />
      )}

      {showPanel !== null && (
        <PlayerPanelModal player={players[showPanel]} onClose={() => setShowPanel(null)} />
      )}

      {showTrade && (
        <TradeModal players={players} onClose={() => setShowTrade(false)} executeTrade={handleTrade} />
      )}
    </div>
  );
}

